335	    private ObjectNode buildCertificateSummary(Certificate cert) {
336	        ObjectNode node = objectMapper.createObjectNode();
337	        node.put("CertificateArn", cert.getArn());
338	        node.put("DomainName", cert.getDomainName());
339	
340	        ArrayNode sans = objectMapper.createArrayNode();
341	        if (cert.getSubjectAlternativeNames() != null) {
342	            cert.getSubjectAlternativeNames().forEach(sans::add);
343	        }
344	        node.set("SubjectAlternativeNameSummaries", sans);
345	        node.put("HasAdditionalSubjectAlternativeNames", false);
346	
347	        node.put("Status", cert.getStatus().name());
348	        node.put("Type", cert.getType().name());
349	
350	        if (cert.getKeyAlgorithm() != null) {
351	            node.put("KeyAlgorithm", cert.getKeyAlgorithm().getAwsName());
352	        }
353	
354	        ArrayNode keyUsages = objectMapper.createArrayNode();
355	        keyUsages.add("DIGITAL_SIGNATURE");
356	        keyUsages.add("KEY_ENCIPHERMENT");
357	        node.set("KeyUsages", keyUsages);
358	
359	        ArrayNode extKeyUsages = objectMapper.createArrayNode();
360	        extKeyUsages.add("TLS_WEB_SERVER_AUTHENTICATION");
361	        extKeyUsages.add("TLS_WEB_CLIENT_AUTHENTICATION");
362	        node.set("ExtendedKeyUsages", extKeyUsages);
363	
364	        if (cert.getCreatedAt() != null) {
365	            node.put("CreatedAt", cert.getCreatedAt().toEpochMilli() / 1000.0);
366	        }
367	        if (cert.getIssuedAt() != null) {
368	            node.put("IssuedAt", cert.getIssuedAt().toEpochMilli() / 1000.0);
369	        }
370	        if (cert.getImportedAt() != null) {
371	            node.put("ImportedAt", cert.getImportedAt().toEpochMilli() / 1000.0);
372	        }
373	        if (cert.getNotBefore() != null) {
374	            node.put("NotBefore", cert.getNotBefore().toEpochMilli() / 1000.0);
375	        }
376	        if (cert.getNotAfter() != null) {
377	            node.put("NotAfter", cert.getNotAfter().toEpochMilli() / 1000.0);
378	        }
379	
380	        node.put("RenewalEligibility", "INELIGIBLE");
381	        node.put("InUse", cert.getInUseBy() != null && !cert.getInUseBy().isEmpty());
382	
383	        return node;
384	    }
