386	    private List<String> parseStringList(JsonNode node) {
387	        if (!node.isArray()) return null;
388	        List<String> list = new ArrayList<>();
389	        node.forEach(n -> list.add(n.asText()));
390	        return list;
391	    }
392	
393	    private Map<String, String> parseTags(JsonNode tagsNode) {
394	        if (!tagsNode.isArray()) return null;
395	        Map<String, String> tags = new HashMap<>();
396	        for (JsonNode tagNode : tagsNode) {
397	            String key = tagNode.path("Key").asText();
398	            String value = tagNode.path("Value").asText(null);
399	            tags.put(key, value);
400	        }
401	        return tags;
402	    }
403	
404	    private ValidationMethod parseValidationMethod(String method) {
405	        if (method == null) return ValidationMethod.DNS;
406	        try {
407	            return ValidationMethod.valueOf(method.toUpperCase());
408	        } catch (IllegalArgumentException e) {
409	            throw new io.github.hectorvent.floci.core.common.AwsException(
410	                "ValidationException",
411	                "Invalid validation method: " + method + ". Must be DNS or EMAIL.",
412	                400);
413	        }
414	    }
415	
416	    private CertificateOptions parseOptions(JsonNode optionsNode) {
417	        if (optionsNode.isMissingNode()) return null;
418	        String ctPref = optionsNode.path("CertificateTransparencyLoggingPreference").asText("ENABLED");
419	        return new CertificateOptions(ctPref, "DISABLED");
420	    }
421	
422	    private List<CertificateStatus> parseCertificateStatuses(JsonNode node) {
423	        if (!node.isArray()) return null;
424	        List<CertificateStatus> list = new ArrayList<>();
425	        for (JsonNode n : node) {
426	            try {
427	                list.add(CertificateStatus.valueOf(n.asText()));
428	            } catch (IllegalArgumentException e) {
429	                LOG.debugv("Ignoring unknown certificate status: {0}", n.asText());
430	            }
431	        }
432	        return list.isEmpty() ? null : list;
433	    }
434	
435	    private List<KeyAlgorithm> parseKeyTypes(JsonNode node) {
436	        if (!node.isArray()) return null;
437	        List<KeyAlgorithm> list = new ArrayList<>();
438	        for (JsonNode n : node) {
439	            KeyAlgorithm alg = KeyAlgorithm.fromAwsName(n.asText());
440	            if (alg != null) {
441	                list.add(alg);
442	            }
443	        }
444	        return list.isEmpty() ? null : list;
445	    }
