@Test
    @Order(15)
    void importInvalidCertificateFails() {
        given()
            .header("X-Amz-Target", "CertificateManager.ImportCertificate")
            .contentType(ACM_CONTENT_TYPE)
            .body("""
                {
                    "Certificate": "not-a-valid-certificate",
                    "PrivateKey": "not-a-valid-key"
                }
                """)
        .when()
            .post("/")
        .then()
            .statusCode(400)
            .body("__type", equalTo("ValidationException"));
    }

    // ==================== Bug Reproduction Tests ====================

    /**
     * Reproduces Bug 1: ImportCertificate fails when Certificate and PrivateKey
     * are sent as base64-encoded (the AWS CLI behavior).
     * The AWS CLI sends blob values as base64-encoded strings per the JSON 1.1 protocol.
     */
    @Test
    @Order(20)
    void importCertificateWithBase64EncodedBlobs() {
        // Encode the certificate and key as base64 (simulating AWS CLI behavior)
        String certBase64 = Base64.getEncoder().encodeToString(validTestCertificate.getBytes());
        String keyBase64 = Base64.getEncoder().encodeToString(validTestPrivateKey.getBytes());

        String base64ImportedArn = given()
            .header("X-Amz-Target", "CertificateManager.ImportCertificate")
            .contentType(ACM_CONTENT_TYPE)
            .body("""
                {
                    "Certificate": "%s",
                    "PrivateKey": "%s"
                }
                """.formatted(certBase64, keyBase64))
        .when()
            .post("/")
        .then()
            .statusCode(200)
            .body("CertificateArn", startsWith("arn:aws:acm:"))
            .body("CertificateArn", containsString(":certificate/"))
            .extract().jsonPath().getString("CertificateArn");

        // Verify the imported certificate is valid
        given()
            .header("X-Amz-Target", "CertificateManager.DescribeCertificate")
            .contentType(ACM_CONTENT_TYPE)
            .body("""
                {
                    "CertificateArn": "%s"
                }
                """.formatted(base64ImportedArn))
        .when()
            .post("/")
        .then()
            .statusCode(200)
            .body("Certificate.DomainName", equalTo("test-import.example.com"))
            .body("Certificate.Status", equalTo("ISSUED"))
            .body("Certificate.Type", equalTo("IMPORTED"));
    }

    /**
     * Reproduces Bug 2: ExportCertificate fails for IMPORTED certificates.
     * In real AWS ACM, imported certificates can be exported.
     */
    @Test
    @Order(21)
    void exportImportedCertificate() {
        String passphrase = Base64.getEncoder().encodeToString("testpassphrase".getBytes());

        given()
            .header("X-Amz-Target", "CertificateManager.ExportCertificate")
            .contentType(ACM_CONTENT_TYPE)
            .body("""
                {
                    "CertificateArn": "%s",
                    "Passphrase": "%s"
                }
                """.formatted(importedCertificateArn, passphrase))
        .when()
            .post("/")
        .then()
            .statusCode(200)
            .body("Certificate", startsWith("-----BEGIN CERTIFICATE-----"))
            .body("PrivateKey", startsWith("-----BEGIN ENCRYPTED PRIVATE KEY-----"));
    }
}

